// pages/Progress.jsx — Track completed topics and quiz scores
import React, { useState } from "react";
import { Link } from "react-router-dom";
import { TOPICS } from "../data/topicsData";
import {
  getCompletedTopics,
  getQuizScores,
  clearProgress,
} from "../utils/progress";

export default function Progress() {
  const [completed, setCompleted] = useState(getCompletedTopics());
  const [quizScores, setQuizScores] = useState(getQuizScores());

  const handleClear = () => {
    if (window.confirm("Clear all progress data?")) {
      clearProgress();
      setCompleted([]);
      setQuizScores([]);
    }
  };

  const pctDone = Math.round((completed.length / TOPICS.length) * 100);
  const avgScore =
    quizScores.length > 0
      ? Math.round(
          quizScores.reduce((sum, s) => sum + (s.score / s.total) * 100, 0) /
            quizScores.length
        )
      : null;

  return (
    <main className="max-w-3xl mx-auto px-5 py-10">
      <h1 className="text-xl font-semibold text-white mb-1">Progress</h1>
      <p className="text-sm text-muted mb-8">Your learning activity across AptiPrep.</p>

      {/* ── Stats ──────────────────────────────── */}
      <div className="border-t border-border pt-6 mb-8 flex flex-col sm:flex-row gap-8">
        <div>
          <p className="text-xs font-mono text-muted uppercase tracking-widest mb-1">
            Topics Viewed
          </p>
          <p className="text-2xl font-semibold text-white">
            {completed.length}
            <span className="text-sm text-muted font-normal ml-1">/ {TOPICS.length}</span>
          </p>
          <p className="text-xs text-muted mt-1">{pctDone}% complete</p>
        </div>

        <div>
          <p className="text-xs font-mono text-muted uppercase tracking-widest mb-1">
            Quizzes Taken
          </p>
          <p className="text-2xl font-semibold text-white">{quizScores.length}</p>
        </div>

        {avgScore !== null && (
          <div>
            <p className="text-xs font-mono text-muted uppercase tracking-widest mb-1">
              Avg Quiz Score
            </p>
            <p className="text-2xl font-semibold text-white">{avgScore}%</p>
          </div>
        )}
      </div>

      {/* ── Progress bar ───────────────────────── */}
      <div className="mb-10">
        <div className="h-1 bg-subtle rounded-full">
          <div
            className="h-1 bg-accent rounded-full transition-all"
            style={{ width: `${pctDone}%` }}
          />
        </div>
      </div>

      {/* ── Completed topics list ──────────────── */}
      <section className="mb-10">
        <h2 className="text-xs font-mono text-muted uppercase tracking-widest mb-4">
          Topics Viewed
        </h2>
        {completed.length === 0 ? (
          <p className="text-sm text-muted">
            None yet.{" "}
            <Link to="/" className="text-accent hover:underline">
              Start learning
            </Link>
            .
          </p>
        ) : (
          <ul className="space-y-0 list-none m-0 p-0">
            {TOPICS.filter((t) => completed.includes(t.slug)).map((t) => (
              <li key={t.slug} className="border-b border-border">
                <Link
                  to={`/topic/${t.slug}`}
                  className="flex items-center justify-between py-2.5 group no-underline"
                >
                  <span className="text-sm text-gray-300 group-hover:text-white transition-colors">
                    {t.name}
                  </span>
                  <span className="text-xs text-green-500 font-mono">✓</span>
                </Link>
              </li>
            ))}
          </ul>
        )}
      </section>

      {/* ── Quiz history ───────────────────────── */}
      <section className="mb-10">
        <h2 className="text-xs font-mono text-muted uppercase tracking-widest mb-4">
          Quiz History
        </h2>
        {quizScores.length === 0 ? (
          <p className="text-sm text-muted">
            No quizzes taken yet.{" "}
            <Link to="/quiz" className="text-accent hover:underline">
              Take a quiz
            </Link>
            .
          </p>
        ) : (
          <ul className="space-y-0 list-none m-0 p-0">
            {[...quizScores].reverse().map((s, i) => (
              <li
                key={i}
                className="border-b border-border py-3 flex items-center justify-between"
              >
                <div>
                  <p className="text-sm text-gray-300">{s.topic}</p>
                  <p className="text-xs text-muted">
                    {new Date(s.date).toLocaleDateString("en-IN", {
                      day: "numeric",
                      month: "short",
                      year: "numeric",
                    })}
                  </p>
                </div>
                <span
                  className={`text-sm font-mono ${
                    s.score / s.total >= 0.8
                      ? "text-green-400"
                      : s.score / s.total >= 0.5
                      ? "text-yellow-400"
                      : "text-red-400"
                  }`}
                >
                  {s.score}/{s.total}
                </span>
              </li>
            ))}
          </ul>
        )}
      </section>

      {/* Clear button */}
      <button
        onClick={handleClear}
        className="text-xs text-muted hover:text-red-400 transition-colors"
      >
        Clear all progress
      </button>

      <div className="h-16" />
    </main>
  );
}
